module accu
(
    input clk,
    input rst_n,
    input [7:0] data_in,
    input valid_in,
    output reg valid_out,
    output reg [9:0] data_out
);
// TODO: implement your sequential logic here
always @(posedge clk or negedge rst_n) begin
    if(!rst_n) begin
        data_out <= 10'b0;
        valid_out <= 1'b0;
    end
    else if(valid_in == 1'b1) begin
        data_out <= data_out + data_in;
        valid_out <= 1'b0;
    end
    else if(valid_in == 1'b0) begin
        data_out <= data_out;
        valid_out <= 1'b0;
    end
    else begin
        data_out <= data_out;
        valid_out <= 1'b0;
    end
end
endmodule
